command:
let mouseX = foundry.utils.getProperty(canvas,"mousePosition.x");
let mouseY = foundry.utils.getProperty(canvas,"mousePosition.y");
let tile = canvas.scene.tiles.find(x => x.flags.dsa5.x>=0 && x.flags.dsa5.y>=0 && x.x<=mouseX && x.y<=mouseY && x.x+x.width>=mouseX && x.y+x.height>=mouseY);
if (!tile) {
  return;
}
game.dsa5.apps.minesweeper(tile.flags.dsa5.x, tile.flags.dsa5.y, canvas.scene.uuid, true);
